    with open(review_result, 'r') as f:
        review_data = json.load(f)
else:
    review_data = []

print("Loaded %d businesses and %d reviews" % (len(business_data), len(review_data)))

# Extract state codes and create mapping
business_ref_to_state = {}
state_review_sums = {}

for biz in business_data:
    desc = biz.get('description', '')
    if desc and ',' in desc:
        # Extract state code (e.g., "CA" from "Goleta, CA")
        parts = desc.split(',')
        for part in parts:
            part = part.strip()
            if len(part) == 2 and part.isalpha() and part.isupper():
                state = part
                business_id = biz['business_id']
                business_ref = business_id.replace('businessid_', 'businessref_')
                business_ref_to_state[business_ref] = state
                review_count = int(biz['review_count'])
                state_review_sums[state] = state_review_sums.get(state, 0) + review_count

print("Found %d businesses with state info" % len(business_ref_to_state))
print("State review totals from metadata:", state_review_sums)

# Count actual reviews and ratings by state
state_actual_counts = {}
state_rating_totals = {}

for review in review_data:
    ref = review.get('business_ref', '')
    rating = int(review.get('rating', 0))

    state = business_ref_to_state.get(ref)
    if state:
        state_actual_counts[state] = state_actual_counts.get(state, 0) + 1
        state_rating_totals[state] = state_rating_totals.get(state, 0) + rating

# Find top state by actual review count
if state_actual_counts:
    top_state = max(state_actual_counts, key=state_actual_counts.get)
    top_reviews = state_actual_counts[top_state]
    top_avg = state_rating_totals[top_state] / top_reviews if top_reviews > 0 else 0

    result = {
        'state': top_state,
        'review_count': top_reviews,
        'avg_rating': round(top_avg, 2)
    }
else:
    result = {'error': 'No state data found'}

print("Result:", result)
print('__RESULT__:')
print(json.dumps(result))"}
